do_if.value:
$savail gt 0
                                                    and $ship.gatedistance.{$src.seller} ge 0
                                                    and not @$src.seller.sector.isblacklisted.{blacklisttype.sectoractivity}.{blacklistgroup.civilian}.{$ship}
                                                    and not @$src.seller.sector.isblacklisted.{blacklisttype.sectortravel}.{blacklistgroup.civilian}.{$ship}
                                                    and not $src.seller.isblacklisted.{blacklisttype.objectactivity}.{blacklistgroup.civilian}.{$ship}
                                                    and (not $tgt.restriction.factions.count
                                                         or (if $tgt.restriction.inverted
                                                               then not $tgt.restriction.factions.indexof.{$src.seller.owner}
                                                               else $tgt.restriction.factions.indexof.{$src.seller.owner}))

($o.amount - $taken) gt 0
                              and $dist ge 0
                              and $dist le $MaxJumps
                              and not @$o.buyer.sector.isblacklisted.{blacklisttype.sectoractivity}.{blacklistgroup.civilian}.{$Ship}
                              and not @$o.buyer.sector.isblacklisted.{blacklisttype.sectortravel}.{blacklistgroup.civilian}.{$Ship}
                              and not $o.buyer.isblacklisted.{blacklisttype.objectactivity}.{blacklistgroup.civilian}.{$Ship}
                              and (not @$best or $dist lt $bestdist or ($dist == $bestdist and $phys lt $bestphys))
